(function () {
    'use strict';

    function pluginNetflix() {
      window.plugin_netflix_ready = true;

      // --------------------------------------------------------
      // CSS inject
      // --------------------------------------------------------
      function injectStyles() {
        $('body').append("<style>:root{--nf-bg: #141414;--nf-surface: #181818;--nf-red: #E50914;--nf-red-glow: rgba(229, 9, 20, 0.35);--nf-text: #e5e5e5;--nf-text-dim: #999999;--nf-radius: 1em;--nf-ease: cubic-bezier(0.25, 0.46, 0.45, 0.94);--nf-ease-out: cubic-bezier(0.16, 1, 0.3, 1)}body{background-color:var(--nf-bg) !important}.activity__body .scroll__content{padding-top:.4em !important}.card:not(.card--wide) .card__img{background-color:var(--nf-surface);filter:brightness(0.85);transition:filter .3s var(--nf-ease)}.card:not(.card--wide).focus .card__img,.card:not(.card--wide).hover .card__img{filter:brightness(1.05)}.items-line .scroll--over{overflow:visible}.card:not(.card--wide) .card__view{transition:transform .3s var(--nf-ease),box-shadow .3s var(--nf-ease);border-radius:var(--nf-radius);position:relative;z-index:1}.card:not(.card--wide).focus,.card:not(.card--wide).hover{position:relative;z-index:10}.card:not(.card--wide).focus .card__view,.card:not(.card--wide).hover .card__view{transform:scale(1.12) !important;animation:none !important;box-shadow:0 0 0 2px var(--nf-red),0 8px 32px var(--nf-red-glow) !important}.card:not(.card--wide).focus .card__view::after,.card:not(.card--wide).hover .card__view::after{border:none !important}.card:not(.card--wide).focus .nf-overlay,.card:not(.card--wide).hover .nf-overlay{opacity:1;transform:translateY(0)}.nf-overlay{position:absolute;top:0;left:0;right:0;bottom:0;background:linear-gradient(to top, rgba(0, 0, 0, 0.92) 0%, rgba(0, 0, 0, 0.55) 45%, transparent 100%);border-radius:var(--nf-radius);z-index:2;display:flex;flex-direction:column;justify-content:flex-end;padding:.9em .8em;pointer-events:none;opacity:0;transform:translateY(0.3em);transition:opacity .25s var(--nf-ease),transform .25s var(--nf-ease)}.nf-overlay__title{font-size:.95em;font-weight:600;color:#fff;line-height:1.3;text-shadow:0 1px 4px rgba(0,0,0,.9);overflow:hidden;display:-webkit-box;-webkit-line-clamp:2;line-clamp:2;-webkit-box-orient:vertical}.nf-overlay__meta{font-size:.75em;font-weight:400;color:hsla(0,0%,100%,.7);margin-top:.25em;line-height:1.2;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.card:not(.card--wide) .card__title,.card:not(.card--wide) .card__age{display:none}.nf-hero{position:fixed;left:0;right:0;height:40vh;overflow:hidden;border-radius:var(--nf-radius);z-index:50;pointer-events:none;opacity:0;transform:translateY(0.4em);transition:opacity .35s var(--nf-ease),transform .35s var(--nf-ease);background-color:var(--nf-bg)}body.settings--open .nf-hero{opacity:0 !important;pointer-events:none}.nf-hero--visible{opacity:1;transform:translateY(0)}.nf-hero__img{position:absolute;top:0;left:0;width:100%;height:100%;object-fit:cover;object-position:center top}.nf-hero__gradient{position:absolute;top:0;left:0;right:0;bottom:0;background:linear-gradient(to right, rgba(0, 0, 0, 0.85) 0%, rgba(0, 0, 0, 0.4) 50%, transparent 100%),linear-gradient(to bottom, rgba(0, 0, 0, 0.6) 0%, transparent 40%)}.nf-hero__info{position:absolute;top:1.8em;left:2em;right:42%;z-index:2}.nf-hero__title{font-size:2em;font-weight:700;color:#fff;line-height:1.2;text-shadow:0 2px 8px rgba(0,0,0,.8);margin-bottom:.35em;display:-webkit-box;-webkit-line-clamp:2;line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}.nf-hero__meta{font-size:1em;color:hsla(0,0%,100%,.75);margin-bottom:.4em}.nf-hero__vote{display:inline-block;font-size:1em;font-weight:600;color:var(--nf-red);letter-spacing:.03em;margin-bottom:.6em}.nf-hero__desc{font-size:.95em;color:hsla(0,0%,100%,.65);line-height:1.5;display:-webkit-box;-webkit-line-clamp:3;line-clamp:3;-webkit-box-orient:vertical;overflow:hidden}.items-line__title{font-weight:600;color:var(--nf-text);letter-spacing:.02em}.items-line__more.focus,.items-line__more.hover{background-color:var(--nf-red);border-color:var(--nf-red)}@keyframes nf-logo-intro{0%{opacity:0;transform:scale(3);filter:drop-shadow(0 0 24px var(--nf-red)) brightness(2.5)}60%{opacity:1;filter:drop-shadow(0 0 8px var(--nf-red)) brightness(1.2)}100%{opacity:1;transform:scale(1);filter:none}}.head__logo-icon{animation:nf-logo-intro 1.2s var(--nf-ease) both}@keyframes nf-row-enter{from{opacity:0;transform:translateY(2em)}to{opacity:1;transform:translateY(0)}}@keyframes nf-card-enter{from{opacity:0;transform:translateX(1.5em)}to{opacity:1;transform:translateX(0)}}.items-line.nf-row-animated{animation:nf-row-enter .4s var(--nf-ease-out) both}.items-line.nf-row-animated .card:nth-child(1){animation:nf-card-enter .35s var(--nf-ease-out) 0s both}.items-line.nf-row-animated .card:nth-child(2){animation:nf-card-enter .35s var(--nf-ease-out) 0.04s both}.items-line.nf-row-animated .card:nth-child(3){animation:nf-card-enter .35s var(--nf-ease-out) 0.08s both}.items-line.nf-row-animated .card:nth-child(4){animation:nf-card-enter .35s var(--nf-ease-out) 0.12s both}.items-line.nf-row-animated .card:nth-child(5){animation:nf-card-enter .35s var(--nf-ease-out) 0.16s both}.items-line.nf-row-animated .card:nth-child(6){animation:nf-card-enter .35s var(--nf-ease-out) 0.2s both}.items-line.nf-row-animated .card:nth-child(7){animation:nf-card-enter .35s var(--nf-ease-out) 0.24s both}.items-line.nf-row-animated .card:nth-child(8){animation:nf-card-enter .35s var(--nf-ease-out) 0.28s both}.items-line.nf-row-animated .card:nth-child(9){animation:nf-card-enter .35s var(--nf-ease-out) 0.32s both}.items-line.nf-row-animated .card:nth-child(10){animation:nf-card-enter .35s var(--nf-ease-out) 0.36s both}.items-line.nf-row-animated .card:nth-child(11){animation:nf-card-enter .35s var(--nf-ease-out) 0.4s both}.items-line.nf-row-animated .card:nth-child(12){animation:nf-card-enter .35s var(--nf-ease-out) 0.44s both}.items-line.nf-row-animated .card:nth-child(13){animation:nf-card-enter .35s var(--nf-ease-out) 0.48s both}.items-line.nf-row-animated .card:nth-child(14){animation:nf-card-enter .35s var(--nf-ease-out) 0.52s both}.items-line.nf-row-animated .card:nth-child(15){animation:nf-card-enter .35s var(--nf-ease-out) 0.56s both}.items-line.nf-row-animated .card:nth-child(16){animation:nf-card-enter .35s var(--nf-ease-out) 0.6s both}.items-line.nf-row-animated .card:nth-child(17){animation:nf-card-enter .35s var(--nf-ease-out) 0.64s both}.items-line.nf-row-animated .card:nth-child(18){animation:nf-card-enter .35s var(--nf-ease-out) 0.68s both}.items-line.nf-row-animated .card:nth-child(19){animation:nf-card-enter .35s var(--nf-ease-out) 0.72s both}.items-line.nf-row-animated .card:nth-child(20){animation:nf-card-enter .35s var(--nf-ease-out) 0.76s both}</style>");
        console.log('[netflix] styles injected');
      }

      // --------------------------------------------------------
      // Animation 1: MutationObserver — inject .nf-overlay
      // .card__title — sibling of .card__view (not child),
      // поэтому поднимаемся через closest('.card')
      // --------------------------------------------------------
      function initCardOverlays() {
        var area = document.querySelector('.activitys') || document.querySelector('.wrap__content') || document.body;
        function injectOverlays(root) {
          var views = (root || area).querySelectorAll('.card:not(.card--wide) .card__view:not([data-nf-done])');
          var count = 0;
          for (var i = 0; i < views.length; i++) {
            var view = views[i];
            var card = view.closest ? view.closest('.card') : view.parentNode && view.parentNode.parentNode;
            var title = card ? (card.querySelector('.card__title') || {}).textContent || '' : '';
            view.setAttribute('data-nf-done', '1');
            var titleEl = document.createElement('div');
            titleEl.className = 'nf-overlay__title';
            titleEl.textContent = title;
            var overlay = document.createElement('div');
            overlay.className = 'nf-overlay';
            overlay.appendChild(titleEl);

            // год + жанры
            var cardData = card ? card.card_data : null;
            var year = card ? (card.querySelector('.card__age') || {}).textContent || '' : '';
            var genreStr = '';
            if (cardData) {
              if (cardData.genres && cardData.genres.length) {
                // полные данные (страница деталей)
                genreStr = cardData.genres.slice(0, 2).map(function (g) {
                  return g.name;
                }).join(' | ');
              } else if (cardData.genre_ids && cardData.genre_ids.length) {
                // списки — маппим id→название через встроенный справочник
                try {
                  var cardType = cardData.original_name ? 'tv' : 'movie';
                  var names = Lampa.Api.sources.tmdb.getGenresNameFromIds(cardType, cardData.genre_ids);
                  genreStr = names.slice(0, 2).join(' | ');
                } catch (e) {}
              }
            }
            var metaText = [year, genreStr].filter(Boolean).join('  |  ');
            if (metaText) {
              var metaEl = document.createElement('div');
              metaEl.className = 'nf-overlay__meta';
              metaEl.textContent = metaText;
              overlay.appendChild(metaEl);
            }
            view.appendChild(overlay);
            count++;
          }
          if (count) console.log('[netflix] overlay injected:', count);
        }
        injectOverlays();
        var observer = new MutationObserver(function (mutations) {
          for (var i = 0; i < mutations.length; i++) {
            if (mutations[i].addedNodes.length) {
              injectOverlays();
              break;
            }
          }
        });
        observer.observe(area, {
          childList: true,
          subtree: true
        });
      }

      // --------------------------------------------------------
      // Animation 2: Row whoosh on activity:start
      // Сначала очищаем старые .nf-row-animated — без этого
      // анимация не реплеится при повторном переходе на экран
      // --------------------------------------------------------
      function initRowAnimations() {
        Lampa.Listener.follow('activity', function (e) {
          if (e.type !== 'start') return;
          setTimeout(function () {
            // очистка предыдущей анимации
            var old = document.querySelectorAll('.nf-row-animated');
            for (var i = 0; i < old.length; i++) {
              old[i].classList.remove('nf-row-animated');
            }
            var rows = document.querySelectorAll('.items-line');
            var count = rows.length;
            for (var j = 0; j < rows.length; j++) {
              (function (row, idx) {
                row.style.animationDelay = idx * 0.07 + 's';
                row.classList.add('nf-row-animated');
              })(rows[j], j);
            }
            console.log('[netflix] rows reset and animated:', count);
          }, 50);
        });
      }

      // --------------------------------------------------------
      // Animation 4: Netflix fixed cursor — focused card stays
      // near position 1 (one card visible to the left).
      // Monkey-patches scrollEl.Scroll.update on each row's
      // .scroll element so that when a card gains focus we
      // scroll to cardIndex-1 at the LEFT edge instead of
      // centering the focused card.
      // --------------------------------------------------------
      function initNetflixCursor() {
        function patchScroll(scrollEl) {
          if (!scrollEl || scrollEl._nfPatched) return;
          var scroll = scrollEl.Scroll;
          if (!scroll || typeof scroll.update !== 'function') return;
          var original = scroll.update.bind(scroll);
          scroll.update = function (elem, tocenter) {
            // Only intercept portrait cards in horizontal rows
            if (elem && elem.classList && elem.classList.contains('card') && !elem.classList.contains('card--wide')) {
              var row = scrollEl.closest ? scrollEl.closest('.items-line') : null;
              if (row) {
                var cards = row.querySelectorAll('.card:not(.card--wide)');
                var idx = -1;
                for (var i = 0; i < cards.length; i++) {
                  if (cards[i] === elem) {
                    idx = i;
                    break;
                  }
                }
                if (idx >= 0) {
                  var target = cards[Math.max(0, idx - 1)];
                  console.log('[netflix] cursor fix: card', idx, '→ scroll to', Math.max(0, idx - 1));
                  return original(target, false);
                }
              }
            }
            return original(elem, tocenter);
          };
          scrollEl._nfPatched = true;
          console.log('[netflix] scroll patched on', scrollEl.className || scrollEl.tagName);
        }
        function patchAllRows() {
          var rows = document.querySelectorAll('.items-line .scroll');
          for (var i = 0; i < rows.length; i++) {
            patchScroll(rows[i]);
          }
        }

        // Patch rows that exist now
        patchAllRows();

        // Patch rows added later
        var area = document.querySelector('.activitys') || document.querySelector('.wrap__content') || document.body;
        var observer = new MutationObserver(function (mutations) {
          for (var i = 0; i < mutations.length; i++) {
            if (mutations[i].addedNodes.length) {
              patchAllRows();
              break;
            }
          }
        });
        observer.observe(area, {
          childList: true,
          subtree: true
        });
      }

      // --------------------------------------------------------
      // Hero billboard: position:fixed панель с backdrop под строкой.
      // fixed — не влияет на document flow и расчёты скролла Lampa.
      // --------------------------------------------------------
      function initHeroBillboard() {
        var timer = null;
        var activeRow = null;

        // создаём hero один раз, вешаем на body (fixed — вне потока)
        var hero = document.createElement('div');
        hero.className = 'nf-hero';
        document.body.appendChild(hero);
        function getGenres(cardData) {
          if (cardData.genres && cardData.genres.length) {
            return cardData.genres.slice(0, 3).map(function (g) {
              return g.name;
            }).join(' · ');
          }
          if (cardData.genre_ids && cardData.genre_ids.length) {
            try {
              var ct = cardData.original_name ? 'tv' : 'movie';
              return Lampa.Api.sources.tmdb.getGenresNameFromIds(ct, cardData.genre_ids).slice(0, 3).join(' · ');
            } catch (e) {}
          }
          return '';
        }
        function removeHero() {
          clearTimeout(timer);
          hero.classList.remove('nf-hero--visible');
          activeRow = null;
        }
        function showHero(card, row) {
          var cardData = card.card_data;
          if (!cardData) return;
          var backdropUrl = cardData.backdrop_path ? Lampa.Api.img(cardData.backdrop_path, 'w1280') : '';
          if (!backdropUrl) return;

          // позиционируем fixed-панель под строкой, слегка перекрывая отступ
          var rect = row.getBoundingClientRect();
          var topPos = Math.round(rect.bottom) - 20;
          hero.style.top = topPos + 'px';
          // заполняем пространство до низа экрана (минус небольшой отступ)
          hero.style.height = Math.max(200, window.innerHeight - topPos - 16) + 'px';
          var year = (card.querySelector('.card__age') || {}).textContent || '';
          var title = (card.querySelector('.card__title') || {}).textContent || '';
          var genres = getGenres(cardData);
          var vote = cardData.vote_average ? parseFloat(cardData.vote_average).toFixed(1) : '';
          var meta = [year, genres].filter(Boolean).join('  ·  ');
          hero.innerHTML = '';
          var img = document.createElement('img');
          img.className = 'nf-hero__img';
          img.src = backdropUrl;
          var gradient = document.createElement('div');
          gradient.className = 'nf-hero__gradient';
          var info = document.createElement('div');
          info.className = 'nf-hero__info';
          var titleEl = document.createElement('div');
          titleEl.className = 'nf-hero__title';
          titleEl.textContent = title;
          var metaEl = document.createElement('div');
          metaEl.className = 'nf-hero__meta';
          metaEl.textContent = meta;
          info.appendChild(titleEl);
          if (meta) info.appendChild(metaEl);
          if (vote && parseFloat(vote) > 0) {
            var voteEl = document.createElement('div');
            voteEl.className = 'nf-hero__vote';
            voteEl.textContent = '★ ' + vote;
            info.appendChild(voteEl);
          }
          var overview = cardData.overview || '';
          if (overview) {
            var descEl = document.createElement('div');
            descEl.className = 'nf-hero__desc';
            descEl.textContent = overview;
            info.appendChild(descEl);
          }
          hero.appendChild(img);
          hero.appendChild(gradient);
          hero.appendChild(info);
          activeRow = row;
          hero.offsetHeight; // force reflow for transition
          hero.classList.add('nf-hero--visible');
          console.log('[netflix] hero shown:', title);
        }
        function onCardFocus(card) {
          clearTimeout(timer);
          var row = card.closest ? card.closest('.items-line') : null;
          if (!row) return;
          if (activeRow && activeRow !== row) removeHero();
          timer = setTimeout(function () {
            if (card.classList.contains('focus') || card.classList.contains('hover')) {
              showHero(card, row);
            }
          }, 600);
        }
        var area = document.querySelector('.activitys') || document.querySelector('.wrap__content') || document.body;
        var observer = new MutationObserver(function (mutations) {
          for (var i = 0; i < mutations.length; i++) {
            var el = mutations[i].target;
            if (el.classList && el.classList.contains('card') && !el.classList.contains('card--wide') && el.classList.contains('focus')) {
              onCardFocus(el);
              break;
            }
          }
        });
        observer.observe(area, {
          attributes: true,
          attributeFilter: ['class'],
          subtree: true
        });
        console.log('[netflix] hero observer started');
        Lampa.Listener.follow('activity', function (e) {
          if (e.type === 'start' || e.type === 'back') {
            clearTimeout(timer);
            removeHero();
          }
        });

        // скрываем hero при появлении модальных окон (.modal внутри .wrap)
        var modalObserver = new MutationObserver(function (mutations) {
          for (var i = 0; i < mutations.length; i++) {
            var nodes = mutations[i].addedNodes;
            for (var j = 0; j < nodes.length; j++) {
              if (nodes[j].classList && nodes[j].classList.contains('modal')) {
                clearTimeout(timer);
                hero.classList.remove('nf-hero--visible');
                return;
              }
            }
          }
        });
        modalObserver.observe(document.body, {
          childList: true,
          subtree: true
        });
      }

      // --------------------------------------------------------
      // Init
      // --------------------------------------------------------
      function init() {
        injectStyles();
        initCardOverlays();
        initRowAnimations();
        initNetflixCursor();
        initHeroBillboard();
        console.log('[netflix] plugin ready');
      }
      if (window.appready) init();else {
        Lampa.Listener.follow('app', function (e) {
          if (e.type == 'ready') init();
        });
      }
    }
    if (!window.plugin_netflix_ready) pluginNetflix();

})();
